CREATE TABLE Usuario ( id_usuario INT AUTO_INCREMENT PRIMARY KEY, nome VARCHAR(100) NOT NULL, email VARCHAR(100) NOT NULL UNIQUE, senha VARCHAR(255) NOT NULL, tipo_usuario VARCHAR(20) NOT NULL, telefone VARCHAR(20), data_cadastro DATETIME DEFAULT CURRENT_TIMESTAMP ); CREATE TABLE Paciente ( id_paciente INT AUTO_INCREMENT PRIMARY KEY, id_usuario INT NOT NULL, data_nascimento DATE, FOREIGN KEY (id_usuario) REFERENCES Usuario(id_usuario) ); CREATE TABLE Psicologo ( id_psicologo INT AUTO_INCREMENT PRIMARY KEY, id_usuario INT NOT NULL, crp VARCHAR(20) NOT NULL, valor_consulta DECIMAL(10,2), descricao TEXT, FOREIGN KEY (id_usuario) REFERENCES Usuario(id_usuario) ); CREATE TABLE Especialidade ( id_especialidade INT AUTO_INCREMENT PRIMARY KEY, nome VARCHAR(100) NOT NULL ); CREATE TABLE Psicologo_Especialidade ( id_psicologo INT, id_especialidade INT, PRIMARY KEY (id_psicologo, id_especialidade), FOREIGN KEY (id_psicologo) REFERENCES Psicologo(id_psicologo), FOREIGN KEY (id_especialidade) REFERENCES Especialidade(id_especialidade) ); CREATE TABLE Consulta ( id_consulta INT AUTO_INCREMENT PRIMARY KEY, id_psicologo INT NOT NULL, id_paciente INT NOT NULL, data_consulta DATE NOT NULL, horario TIME NOT NULL, status VARCHAR(30), FOREIGN KEY (id_psicologo) REFERENCES Psicologo(id_psicologo), FOREIGN KEY (id_paciente) REFERENCES Paciente(id_paciente) ); CREATE TABLE Avaliacao ( id_avaliacao INT AUTO_INCREMENT PRIMARY KEY, id_consulta INT NOT NULL, nota INT, comentario TEXT, FOREIGN KEY (id_consulta) REFERENCES Consulta(id_consulta) ); CREATE TABLE Mensagem ( id_mensagem INT AUTO_INCREMENT PRIMARY KEY, id_paciente INT NOT NULL, id_psicologo INT NOT NULL, texto TEXT, data_envio DATETIME DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (id_paciente) REFERENCES Paciente(id_paciente), FOREIGN KEY (id_psicologo) REFERENCES Psicologo(id_psicologo) ); CREATE TABLE Disponibilidade ( id_disponibilidade INT AUTO_INCREMENT PRIMARY KEY, id_psicologo INT NOT NULL, dia_semana VARCHAR(20), hora_inicio TIME,hora_fim TIME, FOREIGN KEY (id_psicologo) REFERENCES Psicologo(id_psicologo) );